SELECT COUNT(*) AS QUANTIDADE_PARTICIPACOES FROM servidor_proj sp JOIN servidor s ON sp.fk_siape = s.pk_siape JOIN proj p ON sp.fk_proj = p.pk WHERE LOWER(p.tipo_projeto) = LOWER('pesquisa') AND LOWER(sp.papel) = LOWER('autor') AND LOWER(s.genero) = LOWER('masculino') AND LOWER(s.area_ingresso) LIKE LOWER('%sociologia%') AND LOWER(s.campus_atual) LIKE LOWER('%itumbiara%') AND p.data_inicio >= (DATE('now', '-5 years'))